with.command:
cd /sandbox/work && python3 - <<'PYEOF'
import os
d='/sandbox/work'
def rd(p):
    try:
        return open(os.path.join(d,p)).read()
    except Exception:
        return ''
html=rd('index.html'); css=rd('style.css'); js=rd('app.js')
out=[]
for line in html.split(chr(10)):
    low=line.lower()
    if '<link' in low and '.css' in low:
        continue
    if '<script' in low and 'src=' in low and '.js' in low:
        continue
    out.append(line)
html=chr(10).join(out)
style='<style>'+chr(10)+css+chr(10)+'</style>'
script='<scr'+'ipt>'+chr(10)+js+chr(10)+'</scr'+'ipt>'
if '</head>' in html:
    html=html.replace('</head>', style+chr(10)+'</head>', 1)
else:
    html=style+html
if '</body>' in html:
    html=html.replace('</body>', script+chr(10)+'</body>', 1)
else:
    html=html+script
open(os.path.join(d,'standalone.html'),'w').write(html)
PYEOF
cat /sandbox/work/standalone.html
